468	export function requireProviderContractProvider(providerId: string): ProviderPlugin {
469	  const pluginIds = providerContractPluginIdsByProviderId.get(providerId) ?? [];
470	  const entries = loadProviderContractEntriesForPluginIds(pluginIds);
471	  const provider = entries.find((entry) => entry.provider.id === providerId)?.provider;
472	  if (!provider) {
