474	      ...new Map(entries.map((entry) => [entry.provider.id, entry.provider])).values(),
475	    ];
476	    // Paired catalogs may expose multiple runtime provider ids from one shared
477	    // ProviderPlugin contract entry. Reuse that single contract surface for the
478	    // manifest-owned alias ids instead of requiring duplicate registration.
479	    if (pluginIds.length === 1 && pluginScopedProviders.length === 1) {
480	      return pluginScopedProviders[0];
481	    }
482	    if (providerContractLoadError) {
483	      throw new Error(
484	        `provider contract entry missing for ${providerId}; bundled provider registry failed to load: ${providerContractLoadError.message}`,
485	      );
486	    }
487	    throw new Error(`provider contract entry missing for ${providerId}`);
488	  }
489	  return provider;
