271	export type ChannelGatewayContext<ResolvedAccount = unknown> = {
272	  cfg: OpenClawConfig;
273	  accountId: string;
274	  account: ResolvedAccount;
275	  runtime: RuntimeEnv;
276	  abortSignal: AbortSignal;
