6	export function isChannelTarget(target: string): boolean {
7	  return target.startsWith("#") || target.startsWith("&");
8	}
9	
10	export function normalizeIrcMessagingTarget(raw: string): string | undefined {
11	  const trimmed = raw.trim();
12	  if (!trimmed) {
13	    return undefined;
14	  }
15	  let target = trimmed;
16	  const lowered = target.toLowerCase();
17	  if (lowered.startsWith("irc:")) {
18	    target = target.slice("irc:".length).trim();
19	  }
20	  if (target.toLowerCase().startsWith("channel:")) {
21	    target = target.slice("channel:".length).trim();
22	    if (!target.startsWith("#") && !target.startsWith("&")) {
23	      target = `#${target}`;
24	    }
25	  }
26	  if (target.toLowerCase().startsWith("user:")) {
27	    target = target.slice("user:".length).trim();
28	  }
29	  if (!target || !looksLikeIrcTargetId(target)) {
30	    return undefined;
31	  }
32	  return target;
33	}
