// Per-board configuration (mirrors IrcChannelConfig structure).
export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: Record<string, GroupToolPolicyConfig>;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** PulseBoard server base URL, e.g. "https://pulseboard.example.com". */
  serverUrl?: string;
  /** API authentication token. */
  token?: string;
  /** Path to a file containing the API token. */
  tokenFile?: string;
  /** Bot username on PulseBoard. */
  username?: string;
  /** Board names to subscribe to on connect (e.g. ["#general", "#help"]). */
  boards?: string[];
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  /** Per-board configuration keyed by board name (e.g. "#general"). */
  groups?: Record<string, PulseBoardBoardConfig>;
  defaultTo?: string;
  textChunkLimit?: number;
  blockStreaming?: boolean;
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
  markdown?: MarkdownConfig;
  dms?: Record<string, DmConfig>;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

/** An inbound message received from PulseBoard. */
export type PulseBoardInboundMessage = {
  messageId: string;
  /**
   * Conversation target:
   * - "#board-name" for board posts (group)
   * - sender "@username" for direct messages
   */
  target: string;
  /** Sender's user id, always "@username" format. */
  senderId: string;
  senderName?: string;
  text: string;
  timestamp: number;
  /** true = board post, false = direct message. */
  isGroup: boolean;
};

export type PulseBoardProbe = BaseProbeResult<string> & {
  serverUrl: string;
  username: string;
  latencyMs?: number;
};

