export const pulseBoardConfigUiHints = {
  "": {
    label: "PulseBoard",
    help: "PulseBoard channel configuration. Connect to a PulseBoard server to receive messages on named boards and via direct messages.",
  },
  serverUrl: {
    label: "PulseBoard Server URL",
    help: "Base URL of the PulseBoard server (e.g. https://pulseboard.example.com). Also configurable via PULSEBOARD_SERVER_URL env var.",
  },
  token: {
    label: "PulseBoard API Token",
    help: "API authentication token for the PulseBoard server. Also configurable via PULSEBOARD_TOKEN env var.",
    tags: ["sensitive"],
  },
  tokenFile: {
    label: "PulseBoard Token File",
    help: "Optional file path containing the PulseBoard API token. Preferred over inline token for production deployments.",
    tags: ["sensitive"],
  },
  username: {
    label: "PulseBoard Username",
    help: "The bot username on PulseBoard (without '@' prefix). Also configurable via PULSEBOARD_USERNAME env var.",
  },
  boards: {
    label: "PulseBoard Boards",
    help: 'Boards to subscribe to on connect (e.g. ["#general", "#help"]). Board names must start with "#".',
  },
  dmPolicy: {
    label: "PulseBoard DM Policy",
    help: 'Direct message access control. "pairing" (recommended) requires explicit approval; "open" allows all DMs (requires allowFrom=["*"]).',
  },
  groupPolicy: {
    label: "PulseBoard Group Policy",
    help: 'Controls which boards trigger agent replies. "allowlist" (default) requires boards to be listed in groups; "open" allows any board (mention-gated).',
  },
  textChunkLimit: {
    label: "PulseBoard Text Chunk Limit",
    help: "Maximum characters per outbound message chunk (max 4000, PulseBoard platform limit).",
  },
} satisfies Record<string, ChannelConfigUiHint>;

