// Fictional PulseBoard protocol client.
// PulseBoard is an imaginary real-time bulletin board platform; this module
// defines the client interface and a stub implementation that models what a
// real WebSocket/HTTP-based client would look like.

export type PulseBoardInboundEvent = {
  kind: "board" | "dm";
  messageId: string;
  senderId: string;
  senderName?: string;
  /** "#board-name" for board posts, sender "@username" for DMs. */
  target: string;
  text: string;
  timestamp: number;
};

export type PulseBoardClientOptions = {
  serverUrl: string;
  token: string;
  username: string;
  /** Boards to subscribe to on connect. */
  boards?: string[];
  connectTimeoutMs?: number;
