import type { DmPolicy } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  createAllowFromSection,
  createPromptParsedAllowFromForAccount,
  createStandardChannelSetupStatus,
  setSetupChannelEnabled,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard, WizardPrompter } from "openclaw/plugin-sdk/setup";
import { formatDocsLink } from "openclaw/plugin-sdk/setup";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
} from "./accounts.js";
import {
  isBoardTarget,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardMessagingTarget,
} from "./normalize.js";
import {
  pulseBoardSetupAdapter,
  setPulseBoardAllowFrom,
  setPulseBoardBoards,
  setPulseBoardDmPolicy,
  updatePulseBoardAccountConfig,
} from "./setup-core.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;

function parseListInput(raw: string): string[] {
  return raw
    .split(/[\n,;]+/g)
    .map((entry) => entry.trim())
    .filter(Boolean);
}

function normalizeBoardEntry(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed || trimmed === "*") {
    return trimmed || null;
  }
  const normalized = normalizePulseBoardMessagingTarget(trimmed) ?? trimmed;
  if (isBoardTarget(normalized)) {
    return normalized;
  }
  // Add "#" prefix if missing.
  return `#${normalized.replace(/^#+/, "")}`;
}

const promptPulseBoardAllowFrom = createPromptParsedAllowFromForAccount<CoreConfig>({
  defaultAccountId: (cfg) => resolveDefaultPulseBoardAccountId(cfg),
  noteTitle: "PulseBoard DM allowlist",
  noteLines: [
    "Allowlist PulseBoard DMs by sender username.",
    "Examples:",
    "- alice",
    "- alice_bot",
    "Multiple entries: comma-separated.",
  ],
  message: "PulseBoard allowFrom (username without @)",
  placeholder: "alice, bob_user",
  parseEntries: (raw) => ({
    entries: parseListInput(raw)
      .map((entry) => normalizePulseBoardAllowEntry(entry))
      .filter(Boolean),
  }),
  getExistingAllowFrom: ({ cfg }) => cfg.channels?.pulseboard?.allowFrom ?? [],
  applyAllowFrom: ({ cfg, allowFrom }) => setPulseBoardAllowFrom(cfg, allowFrom),
});

const pulseBoardDmPolicy: ChannelSetupDmPolicy = {
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg as CoreConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  setPolicy: (cfg, policy) => setPulseBoardDmPolicy(cfg as CoreConfig, policy),
  promptAllowFrom: async ({ cfg, prompter, accountId }) =>
    await promptPulseBoardAllowFrom({
      cfg: cfg as CoreConfig,
      prompter,
      accountId,
    }),
};

async function promptBoards(params: {
  cfg: CoreConfig;
  prompter: WizardPrompter;
  accountId: string;
}): Promise<CoreConfig> {
  const existing = params.cfg.channels?.pulseboard?.boards ?? [];
  const wants = await params.prompter.confirm({
    message: existing.length > 0 ? "Update board subscriptions?" : "Subscribe to specific boards?",
    initialValue: existing.length > 0,
  });
  if (!wants) {
    return params.cfg;
  }

  const raw = String(
    await params.prompter.text({
      message: "Boards to subscribe to (comma-separated, e.g. #general, #help)",
      initialValue: existing.join(", "),
      validate: (value) => {
        const entries = parseListInput(String(value ?? ""));
        if (entries.length === 0) {
          return "Enter at least one board name, or cancel.";
        }
        return undefined;
      },
    }),
  );

  const boards = parseListInput(raw)
    .map((entry) => normalizeBoardEntry(entry))
    .filter((entry): entry is string => entry !== null);

  return setPulseBoardBoards(params.cfg, params.accountId, boards);
}

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs server URL + token + username",
    configuredHint: "configured",
    unconfiguredHint: "needs server URL + token + username",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseBoardAccountIds(cfg as CoreConfig).some(
        (accountId) =>
          resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs a server URL, an API token, and a username.",
      "Boards are named with a '#' prefix (e.g. #general, #help).",
      "Direct messages target users with '@' (e.g. @alice).",
      'Set channels.pulseboard.groupPolicy="allowlist" and channels.pulseboard.groups for board access control.',
      "Boards are mention-gated by default. To allow unmentioned replies, set requireMention=false.",
      "Env vars supported: PULSEBOARD_SERVER_URL, PULSEBOARD_TOKEN, PULSEBOARD_USERNAME.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  prepare: async ({ cfg, accountId, prompter }) => {
    let current = cfg as CoreConfig;

    // Detect env var credentials and offer to use them.
    const hasEnvToken =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_TOKEN?.trim());
    const hasEnvUrl =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_SERVER_URL?.trim());
    const hasEnvUsername =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_USERNAME?.trim());

    if (hasEnvToken && hasEnvUrl && hasEnvUsername) {
      const useEnv = await prompter.confirm({
        message:
          "PULSEBOARD_SERVER_URL, PULSEBOARD_TOKEN, and PULSEBOARD_USERNAME detected. Use env vars?",
        initialValue: true,
      });
      if (useEnv) {
        return setSetupChannelEnabled(current, channel, accountId, true);
      }
    }

    return current;
  },
  run: async ({ cfg, accountId, prompter }) => {
    let current = cfg as CoreConfig;
    const resolved = resolvePulseBoardAccount({ cfg: current, accountId });

    // Step 1: Server URL.
    const hasEnvUrl =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_SERVER_URL?.trim());
    if (!hasEnvUrl) {
      const serverUrl = String(
        await prompter.text({
          message: "PulseBoard server URL",
          initialValue: resolved.serverUrl || "",
          placeholder: "https://pulseboard.example.com",
          validate: (value) =>
            String(value ?? "").trim() ? undefined : "Server URL is required.",
        }),
      ).trim();
      current = updatePulseBoardAccountConfig(current, accountId, { serverUrl });
    }

    // Step 2: API token.
    const hasEnvToken =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_TOKEN?.trim());
    if (!hasEnvToken) {
      const token = String(
        await prompter.text({
          message: "PulseBoard API token",
          initialValue: resolved.token ? "(existing token)" : "",
          placeholder: "pb_live_xxxxxxxxxxxx",
          validate: (value) =>
            String(value ?? "").trim() ? undefined : "API token is required.",
        }),
      ).trim();
      if (token && token !== "(existing token)") {
        current = updatePulseBoardAccountConfig(current, accountId, { token });
      }
    }

    // Step 3: Username.
    const hasEnvUsername =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_USERNAME?.trim());
    if (!hasEnvUsername) {
      const username = String(
        await prompter.text({
          message: "PulseBoard username (without @)",
          initialValue: resolved.username || "",
          placeholder: "mybot",
          validate: (value) =>
            String(value ?? "").trim() ? undefined : "Username is required.",
        }),
      ).trim();
      current = updatePulseBoardAccountConfig(current, accountId, {
        username: username.replace(/^@/, ""),
      });
    }

    // Step 4: Board subscriptions (optional).
    current = await promptBoards({ cfg: current, prompter, accountId });

    return current;
  },
  configure: async ({ cfg, accountId, prompter }) => {
    let current = cfg as CoreConfig;

    // Step 5: Allow-from list.
    current = await createAllowFromSection({
      cfg: current,
      channel,
      prompter,
      accountId,
      dmPolicy: pulseBoardDmPolicy,
    });

    return current;
  },
  finish: async ({ cfg }) => {
    return cfg as CoreConfig;
  },
  completionNote: {
    title: "PulseBoard configured",
    lines: [
      "PulseBoard is now set up.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
};

