        (accountId) =>
          resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs a server URL, an API token, and a username.",
      "Boards are named with a '#' prefix (e.g. #general, #help).",
      "Direct messages target users with '@' (e.g. @alice).",
      'Set channels.pulseboard.groupPolicy="allowlist" and channels.pulseboard.groups for board access control.',
      "Boards are mention-gated by default. To allow unmentioned replies, set requireMention=false.",
      "Env vars supported: PULSEBOARD_SERVER_URL, PULSEBOARD_TOKEN, PULSEBOARD_USERNAME.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  prepare: async ({ cfg, accountId, prompter }) => {
    let current = cfg as CoreConfig;

    // Detect env var credentials and offer to use them.
    const hasEnvToken =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_TOKEN?.trim());
    const hasEnvUrl =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_SERVER_URL?.trim());
    const hasEnvUsername =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_USERNAME?.trim());

    if (hasEnvToken && hasEnvUrl && hasEnvUsername) {
      const useEnv = await prompter.confirm({
        message:
          "PULSEBOARD_SERVER_URL, PULSEBOARD_TOKEN, and PULSEBOARD_USERNAME detected. Use env vars?",
        initialValue: true,
      });
      if (useEnv) {
        return setSetupChannelEnabled(current, channel, accountId, true);
      }
    }

    return current;
  },
  run: async ({ cfg, accountId, prompter }) => {
    let current = cfg as CoreConfig;
    const resolved = resolvePulseBoardAccount({ cfg: current, accountId });

    // Step 1: Server URL.
    const hasEnvUrl =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_SERVER_URL?.trim());
    if (!hasEnvUrl) {
      const serverUrl = String(
        await prompter.text({
          message: "PulseBoard server URL",
          initialValue: resolved.serverUrl || "",
          placeholder: "https://pulseboard.example.com",
          validate: (value) =>
            String(value ?? "").trim() ? undefined : "Server URL is required.",
        }),
      ).trim();
      current = updatePulseBoardAccountConfig(current, accountId, { serverUrl });
    }

    // Step 2: API token.
    const hasEnvToken =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_TOKEN?.trim());
    if (!hasEnvToken) {
      const token = String(
        await prompter.text({
          message: "PulseBoard API token",
          initialValue: resolved.token ? "(existing token)" : "",
          placeholder: "pb_live_xxxxxxxxxxxx",
          validate: (value) =>
            String(value ?? "").trim() ? undefined : "API token is required.",
        }),
      ).trim();
      if (token && token !== "(existing token)") {
        current = updatePulseBoardAccountConfig(current, accountId, { token });
      }
    }

    // Step 3: Username.
    const hasEnvUsername =
      accountId === DEFAULT_ACCOUNT_ID && Boolean(process.env.PULSEBOARD_USERNAME?.trim());
    if (!hasEnvUsername) {
      const username = String(
        await prompter.text({
          message: "PulseBoard username (without @)",
          initialValue: resolved.username || "",
          placeholder: "mybot",
          validate: (value) =>
            String(value ?? "").trim() ? undefined : "Username is required.",
        }),
      ).trim();
      current = updatePulseBoardAccountConfig(current, accountId, {
        username: username.replace(/^@/, ""),
      });
    }

    // Step 4: Board subscriptions (optional).
    current = await promptBoards({ cfg: current, prompter, accountId });

    return current;
  },
  configure: async ({ cfg, accountId, prompter }) => {
    let current = cfg as CoreConfig;

    // Step 5: Allow-from list.
    current = await createAllowFromSection({
      cfg: current,
      channel,
      prompter,
      accountId,
      dmPolicy: pulseBoardDmPolicy,
    });

    return current;
  },
  finish: async ({ cfg }) => {
    return cfg as CoreConfig;
  },
  completionNote: {
    title: "PulseBoard configured",
    lines: [
      "PulseBoard is now set up.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
};

